try {
return $input.all()?.filter(item => {
  // Adjust the field names if different in your Airtable
  const shiftStatus = item.json['Shift Status'];      // e.g., "accepted", "rejected", or empty/undefined
  const shiftApproval = item.json['Shift Approval'];  // e.g., "Approved", "Disapproved", "in Progress"

  // Has not replied means "Shift Status" is empty or undefined
  // Not declined means "Shift Approval" is NOT "Disapproved"
  const hasNotReplied = !shiftStatus; // falsy = not replied
  const notDeclined = shiftApproval !== 'Disapproved';

  return hasNotReplied && notDeclined;
});

} catch(e) {
  return [{ json: { error: e.message } }];
}

try {
// This code finds a specific employee's shift for a specific date.

// --- Step 1: Get Data from Previous Nodes ---

// Get the full record of the employee who called off.
const employeeRecord = $('Get a record1').first(); // <-- This line is corrected
// If the employee isn't found in your database, stop.
if (!employeeRecord) {
  return [];
}
const employeeId = employeeRecord.json.id;

// --- Step 2: Define "Today" in Your Timezone ---

// Use standard JavaScript to get today's date in 'dd/MM/yyyy' format for India.
const formatter = new Intl.DateTimeFormat('en-GB', {
  timeZone: 'Asia/Kolkata',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit'
});
const leaveDateStr = formatter.format(new Date());

// --- Step 3: Filter All Shifts ---

// Get the list of all shift records passed into this node.
const allShifts = $input.all();

const todaysShift = allShifts.filter(item => {
  const shift = item.json;

  // Condition 1: Check if the shift belongs to the correct employee.
  // Your 'Employee' field is a linked record (an array of IDs), so we check if the ID is in the array.
  const employeeMatch = Array.isArray(shift.Employee) && shift.Employee.includes(employeeId);

  // If it's not the right employee, skip to the next item.
  if (!employeeMatch) {
    return false;
  }

  // Condition 2: Check if the shift's start date matches today's date.
  const shiftStartDate = new Date(shift.Start);
  const shiftDateStr = formatter.format(shiftStartDate); // Convert shift date to 'dd/MM/yyyy'
  const dateMatch = (shiftDateStr === leaveDateStr);

  // Keep the item only if BOTH the employee and the date match.
  return dateMatch;
});

// Return the result: an array containing only the matching shift, or an empty array if no match was found.
return todaysShift;
} catch(e) {
  return [{ json: { error: e.message } }];
}

try {
// This code calculates the time difference in hours between two timestamps.

// Get the approval submission time from the trigger node.
const submissionTimeStr = $('On form submission').first().json.submittedAt;
const submissionDate = new Date(submissionTimeStr);

// Prepare an array to hold the output items.
const outputItems = [];

// Loop through each record from the 'Search records6' node.
for (const item of $input.all()) {
  // Get the original call-off time for the current record.
  const callOffTimeStr = item.json['Call-Off Date/Time'];

  // Check if both date strings are available before calculating.
  if (callOffTimeStr && submissionTimeStr) {
    const callOffDate = new Date(callOffTimeStr);

    // Calculate the absolute difference in milliseconds.
    const differenceMs = Math.abs(submissionDate - callOffDate);

    // Convert the difference from milliseconds to hours.
    const differenceHours = differenceMs / (1000 * 60 * 60);

    // Add the result as a new field to the current item's JSON data.
    // You can rename 'timeToApproveHours' to whatever you prefer.
    item.json.timeToApproveHours = differenceHours;
  }

  // Add the updated item to our output array.
  outputItems.push(item);
}

// Return all the updated items to the next node in the workflow.
return outputItems;
} catch(e) {
  return [{ json: { error: e.message } }];
}
